import{_ as t}from"./chunks/project-settings_01.CuuUlwv5.js";import{_ as a,o,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Configurações do Projeto","description":"","frontmatter":{},"headers":[],"relativePath":"pt/configuration/project-settings.md","filePath":"pt/configuration/project-settings.md"}'),d={name:"pt/configuration/project-settings.md"};function i(n,e,l,c,m,g){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="configuracoes-do-projeto" tabindex="-1"><i class="ph-fill ph-gear-six"></i> Configurações do Projeto <a class="header-anchor" href="#configuracoes-do-projeto" aria-label="Permalink to &quot;&lt;i class=&quot;ph-fill ph-gear-six&quot;&gt;&lt;/i&gt; Configurações do Projeto&quot;">​</a></h1><p>Todas as configurações globais do WebAP estão centralizadas numa única localização: <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong></p><p><img src="'+t+'" alt=""></p><h2 id="configuracoes-gerais-general-settings" tabindex="-1">Configurações Gerais (General Settings) <a class="header-anchor" href="#configuracoes-gerais-general-settings" aria-label="Permalink to &quot;Configurações Gerais (General Settings)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Parâmetro</th><th style="text-align:left;">Descrição</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Target Min FPS</strong></td><td style="text-align:left;">A linha de base de performance. • Se o FPS atual cair abaixo deste valor (levando em consideração a Margem de Desempenho), o plugin começará a reduzir a qualidade gráfica. • Se o FPS permanecer consistentemente acima dele, o plugin tentará melhorar a qualidade. <em>Recomendação:</em> Defina um valor razoável. Para WebGL, o padrão de facto é <code>60</code>, mas para projetos 3D pesados você pode utilizar <code>30</code>.</td></tr></tbody></table><h2 id="configuracoes-do-indexer-indexer-settings" tabindex="-1">Configurações do Indexer (Indexer Settings) <a class="header-anchor" href="#configuracoes-do-indexer-indexer-settings" aria-label="Permalink to &quot;Configurações do Indexer (Indexer Settings)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Parâmetro</th><th style="text-align:left;">Descrição</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Decrease Cooldown</strong></td><td style="text-align:left;">O tempo (em segundos) que o sistema espera após <em>diminuir</em> a qualidade antes de reavaliar o FPS. <em>Recomendação:</em> Deve ser curto (<code>1.0</code> - <code>2.0</code> s). O sistema deve responder agilmente aos atrasos e &quot;largar o lastro&quot; até o FPS estabilizar.</td></tr><tr><td style="text-align:left;"><strong>Increase Cooldown</strong></td><td style="text-align:left;">O tempo de espera após <em>aumentar</em> a qualidade. <em>Recomendação:</em> Deve ser longo (<code>5.0</code> - <code>10.0</code> s). Antes de onerar o sistema de novo, deve verificar que o aumento gráfico prévio não arruinou a estabilidade dos frames.</td></tr></tbody></table><h2 id="anti-yo-yo-penalty-system" tabindex="-1">Anti Yo-Yo Penalty System <a class="header-anchor" href="#anti-yo-yo-penalty-system" aria-label="Permalink to &quot;Anti Yo-Yo Penalty System&quot;">​</a></h2><p>Evita o &quot;efeito ioiô&quot;, onde a qualidade alterna infinitamente entre dois níveis.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Parâmetro</th><th style="text-align:left;">Descrição</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Detection Window</strong></td><td style="text-align:left;">A janela de tempo após <em>aumentar</em> a qualidade durante a qual o sistema monitoriza de perto o FPS. Se ocorrer uma queda de FPS neste período, o sistema classifica isso como Efeito Yo-Yo.</td></tr><tr><td style="text-align:left;"><strong>Penalty Lockout Duration</strong></td><td style="text-align:left;">A duração da penalidade (e.g., <code>60</code> s) durante a qual qualquer tentativa de <em>aumentar</em> a qualidade é categoricamente bloqueada.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Nota</p><p>A penalidade apenas bloqueia aumentos. Se o FPS cair de novo, o sistema ainda pode reduzir a qualidade de emergência.</p></div><h2 id="scalers" tabindex="-1">Scalers <a class="header-anchor" href="#scalers" aria-label="Permalink to &quot;Scalers&quot;">​</a></h2><p>Cada Scaler ativo possui um conjunto de parâmetros de base. Estes parâmetros ditam o seu &quot;custo&quot; para o sistema. O plugin calcula automaticamente esse custo em tempo real: o Scaler com o menor impacto visual e o Target correspondente (CPU/GPU) será invocado primeiro.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Parâmetro</th><th style="text-align:left;">Descrição</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Max Level</strong></td><td style="text-align:left;">O número de passos (níveis) discretos entre a qualidade de base e a mínima. Por exemplo, <code>Max Level = 4</code> significa que este Scaler tem 4 etapas de degradação.</td></tr><tr><td style="text-align:left;"><strong>Min Bound</strong></td><td style="text-align:left;">O valor mínimo de escala (aplicado quando o Scaler atinge o seu <code>Max Level</code>). Por exemplo, <code>0.5</code> dita uma redução de qualidade para 50% do original.</td></tr><tr><td style="text-align:left;"><strong>Max Bound</strong></td><td style="text-align:left;">O valor máximo de escala. Tipicamente igual a <code>1.0</code> (qualidade a 100%), este é o padrão do Nível 0.</td></tr><tr><td style="text-align:left;"><strong>Visual Impact</strong></td><td style="text-align:left;">O impacto visual na renderização (<code>Low</code>, <code>Medium</code>, <code>High</code>). O plugin irá sistematicamente priorizar o aumento do nível (reduzindo a qualidade) para Scalers com impacto <code>Low</code>.</td></tr><tr><td style="text-align:left;"><strong>Target</strong></td><td style="text-align:left;">Especifica qual subsistema o Scaler otimiza (<code>CPU</code>, <code>GPU</code> ou ambos). Se o Gargalo (Bottleneck) atual do sistema for a <code>CPU</code>, o plugin ignorará Scalers focados na <code>GPU</code>.</td></tr><tr><td style="text-align:left;"><strong>Target Tags</strong></td><td style="text-align:left;">Certos Scalers dedicados (<code>WebResolutionScaler</code>, <code>WebCameraClipScaler</code>, <code>WebLayerCullingScaler</code>) aplicam as suas configurações a câmaras específicas na cena em vez de atuar globalmente.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Trabalhando com Tags de Câmara</p><p>Estes Scalers não utilizam uma chamada ao <code>Camera.main</code>. Em vez disso, eles escaneiam as câmaras ativas utilizando o array <code>Target Tags</code>.</p><p>Por padrão, a tag <code>MainCamera</code> é especificada lá. <strong>Se o seu jogo utilizar tags de câmara personalizadas (por exemplo, <code>PlayerCamera</code>), você tem que as adicionar nas configurações do Scaler.</strong> Caso contrário, a escala falhará em ser acionada nessas câmaras.</p></div><h2 id="configuracoes-de-desenvolvimento-development-settings" tabindex="-1">Configurações de Desenvolvimento (Development Settings) <a class="header-anchor" href="#configuracoes-de-desenvolvimento-development-settings" aria-label="Permalink to &quot;Configurações de Desenvolvimento (Development Settings)&quot;">​</a></h2><p>Esta seção é dedicada a depurar o comportamento do plugin no navegador ou no Editor.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Parâmetro</th><th style="text-align:left;">Descrição</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Logging</strong></td><td style="text-align:left;">Permite registrar um rastro detalhado das ações do plugin no console do navegador (ou da Unity). Imprime mensagens sobre as mudanças do Bottleneck, a ativação dos Scalers e o acionamento do Anti Yo-Yo Penalty System.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Otimização</p><p>O registo utiliza os wrappers internos do <code>DebugWebAP</code>. É fortemente recomendado desativar a opção de <code>Logging</code> nas builds de produção (release) para preservar recursos e manter a consola limpa.</p></div>',19)])])}const h=a(d,[["render",i]]);export{f as __pageData,h as default};
